A = (1,1,0);
B = (1,-1,0);
C = (-1,-1,0);
D = (-1,1,0);
E = A + (0,0,1);
F = B + (0,0,3);
G = C + (0,0,4);
H = D + (0,0,2);

draw(surface(E--F--G--H--cycle),gray(0.7),nolight);
draw(E--F--G--H--cycle);
draw(A--E);
draw(B--F);
draw(C--G,dashed);
draw(D--H);
draw(B--A--D);
draw(B--C--D,dashed);
[/asy]

